example.code:
//Example to configure two streaming packets, each with 3 streaming values. The first two values of each packet are sensor values, and the 3rd value of each packet is a static value.
var rxVals = await ueiSdk.UeiClientConfigureUeiStreamingAsync(new UeiStreamingEntry[,]
{
    {UeiSensorId.Td00, UeiSensorId.PowerSumDut00, 123},
    {UeiSensorId.Td04, UeiSensorId.PowerSumDut01, 456}
});
//at this point, user code could optionally validate the data returned in rxVals.

remarks.example:
Example to update the static values in both packets, following the example setup in the description for UeiClientConfigureAndStartUeiStreaming().

var staticValues = new Dictionary<uint, IDictionary<uint, int>>
{
    {0, new Dictionary<uint, int> {{2, 234}}}, //update UEI packet 0's 3rd streaming value (index 2) that was previously configured as a static value.
    {1, new Dictionary<uint, int> {{2, 567}}}, //update UEI packet 1's 3rd streaming value (index 2) that was previously configured as a static value.
};
await ueiSdk.UpdateRctcUeiStreamingStaticValuesAsync(staticValues);

example.code:

const string ueiStreamingName = "UeiStreamingClientName";
await using (var subscription = await ueiSdk.SubscribeToUeiStreamingPacketsAsync(ueiStreamingName))
{
    while (true) //optional. could also put this in a thread...
    {
        Thread.Sleep(TimeSpan.FromSeconds(2)); //delay between loops to let FW send UEI packets and let cached data build up. Max 5s before cached data wraps around.

        var (rxUeiPackets, txUeiPackets) = await subscription.GetLatestCachedUeiStreamingPacketsAsync(Enumerable.Empty<byte>(), Enumerable.Empty<byte>());

        foreach (var (packetIndex, packetList) in txUeiPackets)
        {
            Console.WriteLine($"UEI packets for packetIndex/DUT: {packetIndex}, count: {packetList.Length}");
            foreach (var txPacket in packetList)
            {
                Console.WriteLine("  new packet ");
                for (var i = 0; i < txPacket.Values.Length; i++)
                {
                    Console.Write($"    val[{i}]: {txPacket.Values[i]:X}, ");
                }

                Console.WriteLine();
            }
        }
        //can do the same for rxUeiPackets...
    }
}
